Here are the public test cases for feature10_configurable_storage:
{
  "description": "Alternative configured coupon and redemption storage locations preserve the same externally visible coupon data and redemption timestamp behavior.",
  "cases": [
    {
      "input": {
        "action": "configured_coupon_model",
        "code": "fake-coupon",
        "data": {
          "run-actions": {
            "queue-job": true
          }
        },
        "data_path": [
          "run-actions",
          "queue-job"
        ]
      },
      "expected_output": "storage_table=alternate_coupons\ncoupon_code=fake-coupon\ndata_is_key_value_collection=true\ndata_path_value=true\ndatabase_has_coupon_code=true\n"
    }
  ]
}

